handoff.validation_js:
Vanilla submit handler (IIFE), wraps the form. Validation runs BEFORE the state toggle; on failure it focuses + shakes the first bad field and returns (no advance). The form has `novalidate` so the browser does not pre-block.

```
(function () {
  var form = document.getElementById('gt-form');
  var formView = document.getElementById('gt-form-view');
  var thanksView = document.getElementById('gt-thanks-view');

  form.addEventListener('submit', function (e) {
    e.preventDefault();

    // Minimal validation, highlight the first missing required field.
    var name = form.querySelector('[name="name"]');
    var email = form.querySelector('[name="email"]');
    var audience = form.querySelector('[name="audience"]:checked');
    var firstBad = null;
    if (!name.value.trim()) firstBad = name;
    else if (!email.value.trim() || !/.+@.+\..+/.test(email.value)) firstBad = email;
    else if (!audience) firstBad = form.querySelector('.gt-seg');
    if (firstBad) {
      firstBad.focus && firstBad.focus();
      firstBad.animate && firstBad.animate(
        [{ transform: 'translateX(0)' }, { transform: 'translateX(-6px)' }, { transform: 'translateX(6px)' }, { transform: 'translateX(0)' }],
        { duration: 320 }
      );
      return;
    }

    formView.style.display = 'none';
    thanksView.classList.add('is-active');
    window.scrollTo({ top: 0, behavior: 'auto' });
    fireConfetti();
  });
})();
```
Notes: email regex is exactly `/.+@.+\..+/`. The shake is done via the Web Animations API (`element.animate(...)`) with keyframes translateX 0 -> -6px -> 6px -> 0 over 320ms — NOT a CSS @keyframes (the README's "translateX keyframe ~320ms" maps to this WAAPI call). When the audience radio is unchecked, the shaken/focused target is the whole `.gt-seg` container (radios are visually hidden so they can't take visible focus). In a framework port, replace the display/classList toggle with the `submitted` state flip, and wire the real POST in place of the immediate success (validate -> POST -> on resolve set submitted=true -> fireConfetti).

handoff.confetti_js:
Canvas-based, ~160 pieces, mixed squares+circles, gravity + horizontal drift + rotation, fades after 2600ms and hard-clears by 4000ms. Respects prefers-reduced-motion (builds pieces then returns before animating, so canvas stays blank). NEAR-VERBATIM:

```
function fireConfetti() {
  var canvas = document.getElementById('gt-confetti');
  var ctx = canvas.getContext('2d');
  var W, H;
  function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }
  resize();
  window.addEventListener('resize', resize);

  var colors = ['#C44569', '#E8C465', '#D88B9F', '#59BFE7', '#F4ECDF'];
  var pieces = [];
  var N = 160;
  for (var i = 0; i < N; i++) {
    pieces.push({
      x: W / 2 + (Math.random() - 0.5) * 120,
      y: H * 0.32 + (Math.random() - 0.5) * 60,
      vx: (Math.random() - 0.5) * 14,
      vy: Math.random() * -16 - 4,
      g: 0.32 + Math.random() * 0.2,
      size: 6 + Math.random() * 8,
      color: colors[(Math.random() * colors.length) | 0],
      rot: Math.random() * Math.PI * 2,
      vr: (Math.random() - 0.5) * 0.3,
      shape: Math.random() > 0.5 ? 'rect' : 'circle',
      life: 0
    });
  }

  var reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  if (reduce) return; // respect motion preference, skip animation

  var start = performance.now();
  function frame(t) {
    var elapsed = t - start;
    ctx.clearRect(0, 0, W, H);
    var alive = false;
    for (var i = 0; i < pieces.length; i++) {
      var p = pieces[i];
      p.vy += p.g;
      p.x += p.vx;
      p.y += p.vy;
      p.vx *= 0.99;
      p.rot += p.vr;
      p.life++;
      var alpha = elapsed > 2600 ? Math.max(0, 1 - (elapsed - 2600) / 900) : 1;
      if (p.y < H + 40 && alpha > 0) alive = true;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rot);
      ctx.fillStyle = p.color;
      if (p.shape === 'rect') {
        ctx.fillRect(-p.size / 2, -p.size / 2, p.size, p.size * 0.6);
      } else {
        ctx.beginPath();
        ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.restore();
    }
    if (alive && elapsed < 4000) requestAnimationFrame(frame);
    else ctx.clearRect(0, 0, W, H);
  }
  requestAnimationFrame(frame);
}
```

PHYSICS PRECISELY: origin = horizontal center +/-60px, vertical at 32% of viewport height +/-30px. Initial vx in [-7,7], initial vy in [-20,-4] (upward burst). Per-frame gravity g in [0.32,0.52] added to vy each frame. Horizontal drag vx*=0.99/frame. Rotation: start random 0..2pi, angular velocity vr in [-0.15,0.15] rad/frame. size 6..14px (rects drawn as size x size*0.6, i.e. slightly flat). Color picked uniformly from the 5. Fade: alpha=1 until 2600ms, then linear ramp to 0 over the next 900ms (done by ~3500ms). Loop stops when no piece is both on-screen (y<H+40) and alpha>0, or hard cap at elapsed>=4000ms, then clears the canvas.

5 COLORS (authoritative, from decoded JS): `['#C44569','#E8C465','#D88B9F','#59BFE7','#F4ECDF']`. WATCH OUT: the README lists the 5th as `#FBF6EE`; the actual reference uses `#F4ECDF` (warm cream). Use the reference value for fidelity. README also says "swap in canvas-confetti if you want" — fine, but match these 5 colors and ~160 count. SHAPES: 'rect' (square-ish, fillRect) vs 'circle' (arc), ~50/50. SSR/Astro note: this touches document/window/canvas — run client-side only (e.g. inside the submit handler in a client script / island), never at module top-level during SSR.
